const rows = $input.all().map(i => i.json).sort((a, b) => a.month < b.month ? -1 : 1);
const last = rows[rows.length - 1] || {};
const prev = rows[rows.length - 2] || {};
const mrr = parseFloat(last.mrr || 0);
const prevMrr = parseFloat(prev.mrr || 1);
const mrrGrowth = ((mrr - prevMrr) / prevMrr * 100).toFixed(1);
const churnPct = (parseFloat(last.churn_mrr || 0) / prevMrr * 100).toFixed(2);
const target = parseFloat($env.REVENUE_MRR_TARGET || 5);
const healthy = parseFloat(mrrGrowth) >= target && parseFloat(churnPct) < 5;
return [{ json: { month: last.month, mrr, arr: mrr * 12, mrr_growth_pct: mrrGrowth, churn_pct: churnPct, customers: last.customers, new_mrr: last.new_mrr, expansion_mrr: last.expansion_mrr, contraction_mrr: last.contraction_mrr, health: healthy ? 'healthy' : 'at_risk', target_growth_pct: target } }];

